# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json
import uuid
from typing import Dict, List, Set
from dataclasses import dataclass
from datetime import datetime

@dataclass
class Item:
    id: str
    name: str
    type: str
    value: int
    owner_id: str

@dataclass
class Player:
    id: str
    username: str
    inventory: Dict[str, int]  # item_id -> quantity
    websocket: websockets.WebSocketServerProtocol

class InventorySystem:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.trade_requests: Dict[str, Dict] = {}
        self.lock = asyncio.Lock()

    async def register_player(self, websocket, username: str):
        player_id = str(uuid.uuid4())
        player = Player(player_id, username, {}, websocket)
        self.players[player_id] = player
        await self.send_message(websocket, {
            "type": "player_registered",
            "player_id": player_id
        })
        return player_id

    async def unregister_player(self, player_id: str):
        if player_id in self.players:
            del self.players[player_id]

    async def add_item_to_player(self, player_id: str, item_id: str, quantity: int = 1):
        async with self.lock:
            if player_id not in self.players:
                return False
            if item_id not in self.items:
                return False
            
            player = self.players[player_id]
            if item_id not in player.inventory:
                player.inventory[item_id] = 0
            player.inventory[item_id] += quantity
            
            item = self.items[item_id]
            item.owner_id = player_id
            
            return True

    async def remove_item_from_player(self, player_id: str, item_id: str, quantity: int = 1):
        async with self.lock:
            if player_id not in self.players:
                return False
            if item_id not in self.players[player_id].inventory:
                return False
            
            player = self.players[player_id]
            if player.inventory[item_id] < quantity:
                return False
            
            player.inventory[item_id] -= quantity
            if player.inventory[item_id] == 0:
                del player.inventory[item_id]
            
            return True

    async def create_item(self, name: str, item_type: str, value: int, owner_id: str = None):
        item_id = str(uuid.uuid4())
        item = Item(item_id, name, item_type, value, owner_id or "system")
        self.items[item_id] = item
        return item_id

    async def send_message(self, websocket, message: dict):
        try:
            await websocket.send(json.dumps(message))
        except:
            pass

    async def handle_trade_request(self, from_player_id: str, to_player_id: str, item_id: str, quantity: int):
        async with self.lock:
            if from_player_id not in self.players or to_player_id not in self.players:
                return False
            
            if item_id not in self.players[from_player_id].inventory:
                return False
            
            if self.players[from_player_id].inventory[item_id] < quantity:
                return False
            
            trade_id = str(uuid.uuid4())
            self.trade_requests[trade_id] = {
                "from": from_player_id,
                "to": to_player_id,
                "item_id": item_id,
                "quantity": quantity,
                "status": "pending",
                "timestamp": datetime.now().isoformat()
            }
            
            # Notify players
            from_player = self.players[from_player_id]
            to_player = self.players[to_player_id]
            
            await self.send_message(from_player.websocket, {
                "type": "trade_proposed",
                "trade_id": trade_id,
                "to_player": to_player_id,
                "item": item_id,
                "quantity": quantity
            })
            
            await self.send_message(to_player.websocket, {
                "type": "trade_received",
                "trade_id": trade_id,
                "from_player": from_player_id,
                "item": item_id,
                "quantity": quantity
            })
            
            return True

    async def accept_trade(self, trade_id: str):
        async with self.lock:
            if trade_id not in self.trade_requests:
                return False
            
            trade = self.trade_requests[trade_id]
            if trade["status"] != "pending":
                return False
            
            from_player_id = trade["from"]
            to_player_id = trade["to"]
            item_id = trade["item_id"]
            quantity = trade["quantity"]
            
            # Check if players still exist
            if from_player_id not in self.players or to_player_id not in self.players:
                return False
            
            # Check if from player still has the item
            if item_id not in self.players[from_player_id].inventory:
                return False
            
            if self.players[from_player_id].inventory[item_id] < quantity:
                return False
            
            # Execute trade
            await self.remove_item_from_player(from_player_id, item_id, quantity)
            await self.add_item_to_player(to_player_id, item_id, quantity)
            
            # Update trade status
            self.trade_requests[trade_id]["status"] = "completed"
            
            # Notify players
            from_player = self.players[from_player_id]
            to_player = self.players[to_player_id]
            
            await self.send_message(from_player.websocket, {
                "type": "trade_completed",
                "trade_id": trade_id,
                "item": item_id,
                "quantity": quantity,
                "recipient": to_player_id
            })
            
            await self.send_message(to_player.websocket, {
                "type": "trade_completed",
                "trade_id": trade_id,
                "item": item_id,
                "quantity": quantity,
                "sender": from_player_id
            })
            
            return True

    async def decline_trade(self, trade_id: str):
        async with self.lock:
            if trade_id not in self.trade_requests:
                return False
            
            trade = self.trade_requests[trade_id]
            if trade["status"] != "pending":
                return False
            
            trade["status"] = "declined"
            
            from_player = self.players[trade["from"]]
            to_player = self.players[trade["to"]]
            
            await self.send_message(from_player.websocket, {
                "type": "trade_declined",
                "trade_id": trade_id
            })
            
            await self.send_message(to_player.websocket, {
                "type": "trade_declined",
                "trade_id": trade_id
            })
            
            return True

    async def get_player_inventory(self, player_id: str):
        async with self.lock:
            if player_id not in self.players:
                return {}
            return self.players[player_id].inventory

    async def get_item_details(self, item_id: str):
        async with self.lock:
            if item_id not in self.items:
                return None
            item = self.items[item_id]
            return {
                "id": item.id,
                "name": item.name,
                "type": item.type,
                "value": item.value,
                "owner_id": item.owner_id
            }

class GameServer:
    def __init__(self):
        self.inventory_system = InventorySystem()

    async def handle_client(self, websocket, path):
        player_id = None
        try:
            async for message in websocket:
                data = json.loads(message)
                message_type = data.get("type")
                
                if message_type == "register":
                    player_id = await self.inventory_system.register_player(
                        websocket, data.get("username", "Player")
                    )
                
                elif message_type == "create_item":
                    item_id = await self.inventory_system.create_item(
                        data.get("name"),
                        data.get("type"),
                        data.get("value"),
                        player_id
                    )
                    await self.inventory_system.add_item_to_player(player_id, item_id)
                    await self.inventory_system.send_message(websocket, {
                        "type": "item_created",
                        "item_id": item_id
                    })
                
                elif message_type == "trade_request":
                    await self.inventory_system.handle_trade_request(
                        player_id,
                        data.get("to_player_id"),
                        data.get("item_id"),
                        data.get("quantity", 1)
                    )
                
                elif message_type == "accept_trade":
                    await self.inventory_system.accept_trade(data.get("trade_id"))
                
                elif message_type == "decline_trade":
                    await self.inventory_system.decline_trade(data.get("trade_id"))
                
                elif message_type == "get_inventory":
                    inventory = await self.inventory_system.get_player_inventory(player_id)
                    await self.inventory_system.send_message(websocket, {
                        "type": "inventory_response",
                        "inventory": inventory
                    })
                
                elif message_type == "get_item":
                    item_details = await self.inventory_system.get_item_details(data.get("item_id"))
                    await self.inventory_system.send_message(websocket, {
                        "type": "item_details",
                        "item": item_details
                    })
                
        except websockets.exceptions.ConnectionClosed:
            pass
        finally:
            if player_id:
                await self.inventory_system.unregister_player(player_id)

# Start the server
server = GameServer()
start_server = websockets.serve(server.handle_client, "localhost", 8765)
asyncio.get_event_loop().run_until_complete(start_server)
asyncio.get_event_loop().run_forever()